    private inner class SecureWebViewClient : WebViewClient() {

        override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
            val url = request?.url ?: return true
            val host = url.host ?: return true

            // Only allow navigation to whitelisted hosts
            if (host in ALLOWED_HOSTS) {
                // Enforce HTTPS
                if (url.scheme == "https") {
                    return false // Allow WebView to load
                }
                Log.w(TAG, "Blocked non-HTTPS URL: $url")
                return true
            }

            // Open external links in browser
            try {
                val intent = Intent(Intent.ACTION_VIEW, url)
                startActivity(intent)
            } catch (e: Exception) {
                Log.e(TAG, "Cannot open external URL: $url", e)
            }
            return true
        }

        override fun onReceivedSslError(
            view: WebView?,
            handler: SslErrorHandler?,
            error: android.net.http.SslError?
        ) {
            // NEVER proceed on SSL errors in production
            Log.e(TAG, "SSL Error: ${error?.primaryError}")
            handler?.cancel()
            runOnUiThread {
                Toast.makeText(
                    this@MainActivity,
                    "Security error: SSL certificate issue",
                    Toast.LENGTH_LONG
                ).show()
            }
        }

        override fun onReceivedError(
            view: WebView?,
            request: WebResourceRequest?,
            error: WebResourceError?
        ) {
            if (request?.isForMainFrame == true) {
                Log.e(TAG, "Page load error: ${error?.description}")
            }
        }

        override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
            super.onPageStarted(view, url, favicon)
            Log.d(TAG, "Loading: $url")
        }

        override fun onPageFinished(view: WebView?, url: String?) {
            super.onPageFinished(view, url)
            // Inject bridge availability check
            view?.evaluateJavascript(
                """
                (function() {
                    if (window.NativeBridge) {
                        window.dispatchEvent(new CustomEvent('nativeBridgeReady'));
                    }
                })();
                """.trimIndent(),
                null
            )
        }
    }

    // ---- Camera helpers ----

    fun requestCameraAccess(callback: (String?) -> Unit) {
        pendingCameraCallback = callback
        when {
            ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA)
                    == PackageManager.PERMISSION_GRANTED -> {
                launchCamera()
            }
            ActivityCompat.shouldShowRequestPermissionRationale(this, Manifest.permission.CAMERA) -> {
                AlertDialog.Builder(this)
                    .setTitle("Camera Permission")
                    .setMessage("Camera access is needed to take photos.")
                    .setPositiveButton("Grant") { _, _ ->
                        cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                    }
                    .setNegativeButton("Cancel") { _, _ ->
                        callback(null)
                        pendingCameraCallback = null
                    }
                    .show()
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun launchCamera() {
        val photoFile = try {
            createImageFile()
        } catch (ex: IOException) {
            Log.e(TAG, "Error creating image file", ex)
            pendingCameraCallback?.invoke(null)
            pendingCameraCallback = null
            return
        }

        cameraPhotoUri = FileProvider.getUriForFile(
            this,
            "${applicationContext.packageName}.fileprovider",
            photoFile
        )

        val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, cameraPhotoUri)
            addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
        }

        if (takePictureIntent.resolveActivity(packageManager) != null) {
            cameraActivityLauncher.launch(takePictureIntent)
        } else {
            pendingCameraCallback?.invoke(null)
            pendingCameraCallback = null
        }
    }

    @Throws(IOException::class)
    private fun createImageFile(): File {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
        val storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES)
        return File.createTempFile("PHOTO_${timeStamp}_", ".jpg", storageDir)
    }

    private fun uriToBase64(uri: Uri): String? {
        return try {
            val inputStream = contentResolver.openInputStream(uri) ?: return null
            val bytes = inputStream.readBytes()
            inputStream.close()

            // Compress if too large
            val bitmap = android.graphics.BitmapFactory.decodeByteArray(bytes, 0, bytes.size)
            val outputStream = ByteArrayOutputStream()
            bitmap.compress(Bitmap.CompressFormat.JPEG, 80, outputStream)
            val compressedBytes = outputStream.toByteArray()

            "data:image/jpeg;base64," + Base64.encodeToString(compressedBytes, Base64.NO_WRAP)
        } catch (e: Exception) {
            Log.e(TAG, "Error converting URI to base64", e)
            null
        }
    }

    // ---- Push Notification helpers ----

    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            when {
                ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS)
                        == PackageManager.PERMISSION_GRANTED -> {
                    registerForPushNotifications()
                }
                else -> {
                    notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        } else {
            registerForPushNotifications()
        }
    }

    private fun registerForPushNotifications() {
        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
            if (!task.isSuccessful) {
                Log.w(TAG, "FCM token fetch failed", task.exception)
                webView.post {
                    webView.evaluateJavascript(
                        "window.onNativePushToken && window.onNativePushToken(null, 'Failed to get token');",
                        null
                    )
                }
                return@addOnCompleteListener
            }

            val token = task.result
            Log.d(TAG, "FCM Token: $token")

            // Store token securely
            securePrefs.edit().putString("fcm_token", token).apply()

            // Send token to web app
            webView.post {
                webView.evaluateJavascript(
                    "window.onNativePushToken && window.onNativePushToken('$token', null);",
                    null
                )
            }
        }
    }

    // ---- Secure Storage helpers ----

    fun secureStoragePut(key: String, value: String): Boolean {
        return try {
            val sanitizedKey = sanitizeKey(key)
            securePrefs.edit().putString(sanitizedKey, value).apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "Secure storage put error", e)
            false
        }
    }

    fun secureStorageGet(key: String): String? {
        return try {
            val sanitizedKey = sanitizeKey(key)
            securePrefs.getString(sanitizedKey, null)
        } catch (e: Exception) {
            Log.e(TAG, "Secure storage get error", e)
            null
        }
    }

    fun secureStorageRemove(key: String): Boolean {
        return try {
            val sanitizedKey = sanitizeKey(key)
            securePrefs.edit().remove(sanitizedKey).apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "Secure storage remove error", e)
            false
        }
    }

    fun secureStorageClear(): Boolean {
        return try {
            securePrefs.edit().clear().apply()
            true
        } catch (e: Exception) {
            Log.e(TAG, "Secure storage clear error", e)
            false
        }
    }

    private fun sanitizeKey(key: String): String {
        return key.replace(Regex("[^a-zA-Z0-9_.-]"), "_").take(256)
    }

    fun callJavaScript(script: String) {
        webView.post {
            webView.evaluateJavascript(script, null)
        }
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
    }

    override fun onPause() {
        webView.onPause()
        super.onPause()
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }
}

/**
 * JavaScript Interface Bridge
 * Exposed to web content as window.NativeBridge
 *
 * Usage from JavaScript:
 *
 * // Camera
 * NativeBridge.openCamera();
 * window.onNativeCameraResult = function(base64Image) { ... };
 *
 * // Secure Storage
 * NativeBridge.setItem('key', 'value');
 * var value = NativeBridge.getItem('key');
 * NativeBridge.removeItem('key');
 * NativeBridge.clearStorage();
 *
 * // Push Notifications
 * NativeBridge.requestPushPermission();
 * window.onNativePushToken = function(token, error) { ... };
 *
 * // Device Info
 * var info = JSON.parse(NativeBridge.getDeviceInfo());
 *
 * // Show native toast
 * NativeBridge.showToast('Hello from web!');
 */
class NativeBridge(private val activity: MainActivity) {

    companion object {
        private const val TAG = "NativeBridge"
        private const val MAX_STORAGE_VALUE_SIZE = 1024 * 1024 // 1MB limit
        private const val MAX_TOAST_LENGTH = 200
    }

    // ---- Camera ----

    @JavascriptInterface
    fun openCamera() {
        Log.d(TAG, "openCamera called from JS")
        activity.runOnUiThread {
            activity.requestCameraAccess { base64Image ->
                val escapedImage = base64Image?.replace("'", "\\'") ?: ""
                val hasImage = base64Image != null
                activity.callJavaScript(
                    if (hasImage) {
                        "window.onNativeCameraResult && window.onNativeCameraResult('$escapedImage');"
                    } else {
                        "window.onNativeCameraResult && window.onNativeCameraResult(null);"
                    }
                )
            }
        }
    }

    @JavascriptInterface
    fun isCameraAvailable(): Boolean {
        return activity.packageManager.hasSystemFeature(PackageManager.FEATURE_CAMERA_ANY)
    }

    // ---- Secure Local Storage ----

    @JavascriptInterface
    fun setItem(key: String?, value: String?): Boolean {
        if (key.isNullOrBlank()) {
            Log.w(TAG, "setItem: key is null or blank")
            return false
        }
        if (value == null) {
            Log.w(TAG, "setItem: value is null")
            return false
        }
        if (value.length > MAX_STORAGE_VALUE_SIZE) {
            Log.w(TAG, "setItem: value exceeds max size")
            return false
        }
        return activity.secureStoragePut(key, value)
    }

    @JavascriptInterface
    fun getItem(key: String?): String? {
        if (key.isNullOrBlank()) {
            Log.w(TAG, "getItem: key is null or blank")
            return null
        }
        return activity.secureStorageGet(key)
    }

    @JavascriptInterface
    fun removeItem(key: String?): Boolean {
        if (key.isNullOrBlank()) {
            Log.w(TAG, "removeItem: key is null or blank")
            return false
        }
        return activity.secureStorageRemove(key)
    }

    @JavascriptInterface
    fun clearStorage(): Boolean {
        return activity.secureStorageClear()
    }

    // ---- Push Notifications ----

    @JavascriptInterface
    fun requestPushPermission() {
        Log.d(TAG, "requestPushPermission called from JS")
        activity.runOnUiThread {
            activity.requestNotificationPermission()
        }
    }

    @JavascriptInterface
    fun getPushToken(): String? {
        return activity.secureStorageGet("fcm_token")
    }

    @JavascriptInterface
    fun subscribeToPushTopic(topic: String?): Boolean {
        if (topic.isNullOrBlank() || !topic.matches(Regex("^[a-zA-Z0-9_.-]+$"))) {
            Log.w(TAG, "Invalid topic: $topic")
            return false
        }
        return try {
            FirebaseMessaging.getInstance().subscribeToTopic(topic)
            true
        } catch (e: Exception) {
            Log.e(TAG, "Failed to subscribe to topic", e)
            false
        }
    }

    @JavascriptInterface
    fun unsubscribeFromPushTopic(topic: String?): Boolean {
        if (topic.isNullOrBlank() || !topic.matches(Regex("^[a-zA-Z0-9_.-]+$"))) {
            Log.w(TAG, "Invalid topic: $topic")
            return false
        }
        return try {
            FirebaseMessaging.getInstance().unsubscribeFromTopic(topic)
            true
        } catch (e: Exception) {
            Log.e(TAG, "Failed to unsubscribe from topic", e)
            false
        }
    }

    // ---- Device Info ----

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val info = JSONObject().apply {
            put("platform", "android")
            put("osVersion", Build.VERSION.RELEASE)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("appVersion", try {
                activity.packageManager.getPackageInfo(activity.packageName, 0).versionName
            } catch (e: Exception) {
                "unknown"
            })
        }
        return info.toString()
    }

    // ---- Utility ----

    @JavascriptInterface
    fun showToast(message: String?) {
        if (message.isNullOrBlank()) return
        val safeMessage = message.take(MAX_TOAST_LENGTH)
        activity.runOnUiThread {
            Toast.makeText(activity, safeMessage, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun log(level: String?, message: String?) {
        val safeMessage = message?.take(1000) ?: "null"
        when (level?.lowercase()) {
            "error" -> Log.e(TAG, "JS: $safeMessage")
            "warn" -> Log.w(TAG, "JS: $safeMessage")
            "debug" -> Log.d(TAG, "JS: $safeMessage")
            else -> Log.i(TAG, "JS: $safeMessage")
        }
    }

    @JavascriptInterface
    fun hapticFeedback() {
        activity.runOnUiThread {
            @Suppress("DEPRECATION")
            activity.window.decorView.performHapticFeedback(
                android.view.HapticFeedbackConstants.VIRTUAL_KEY
            )
        }
    }

    @JavascriptInterface
    fun shareText(title: String?, text: String?) {
        if (text.isNullOrBlank()) return
        activity.runOnUiThread {
            val sendIntent = Intent().apply {
                action = Intent.ACTION_SEND
                putExtra(Intent.EXTRA_TEXT, text)
                type = "text/plain"
            }
            val shareIntent = Intent.createChooser(sendIntent, title ?: "Share")
            activity.startActivity(shareIntent)
        }
    }
}

/**
 * Firebase Cloud Messaging Service
 * Handles incoming push notifications and token refresh
 */
class AppFirebaseMessagingService : FirebaseMessagingService() {

    companion object {
        private const val TAG = "FCMService"
        private const val NOTIFICATION_CHANNEL_ID = "hybrid_app_channel"
    }

    override fun onNewToken(token: String) {
        super.onNewToken(token)
        Log.d(TAG, "New FCM token: $token")

        // Store token securely
        try {
            val masterKey = MasterKey.Builder(this)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()

            val securePrefs = EncryptedSharedPreferences.create(
                this,
                "secure_hybrid_prefs",
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
            securePrefs.edit().putString("fcm_token", token).apply()
        } catch (e: Exception) {
            Log.e(TAG, "Failed to store new token", e)
        }
    }

    override fun onMessageReceived(remoteMessage: RemoteMessage) {
        super.onMessageReceived(remoteMessage)
        Log.d(TAG, "Message received from: ${remoteMessage.from}")

        val title = remoteMessage.notification?.title ?: remoteMessage.data["title"] ?: "Notification"
        val body = remoteMessage.notification?.body ?: remoteMessage.data["body"] ?: ""

        showNotification(title, body, remoteMessage.data)
    }

    private fun showNotification(title: String, body: String, data: Map<String, String>) {
        val notificationId = System.currentTimeMillis().toInt()

        val builder = NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(body)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true)

        if (ActivityCompat.checkSelfPermission(
                this,
                Manifest.permission.POST_NOTIFICATIONS
            ) == PackageManager.PERMISSION_GRANTED
        ) {
            NotificationManagerCompat.from(this).notify(notificationId, builder.build())
        }
    }
}